const today = new Date().toLocaleDateString('fr-FR');
const inboxRows = $input.all();
if (inboxRows.some(i => i.json && i.json.error)) throw new Error('Unable to read Inbox IA from Notion');
const valueOf = (obj, names) => { for (const name of names) { const value = obj[name]; if (value !== undefined && value !== null && value !== '') return value; } return ''; };
const toText = (value) => { if (value === undefined || value === null) return ''; if (Array.isArray(value)) return value.map(toText).filter(Boolean).join(', '); if (typeof value === 'object') return value.name || value.value || value.plain_text || (value.text && value.text.content) || ''; return value.toString(); };
const toTags = (value) => { if (!value) return []; const tags = Array.isArray(value) ? value : [value]; return tags.map(toText).filter(Boolean); };
const items = [];
for (const input of inboxRows) {
  const j = input.json;
  const p = j.properties || {};
  const data = { ...p, ...j };
  const status = toText(valueOf(data, ['property_status', 'Status', 'status']));
  if (status && status !== 'Inbox') continue;
  const title = toText(valueOf(data, ['property_name', 'name', 'Name', 'Title', 'title']));
  const summary = toText(valueOf(data, ['property_summary', 'summary', 'Summary']));
  const source = toText(valueOf(data, ['property_source', 'source', 'Source']));
  const url = toText(valueOf(data, ['property_url', 'url', 'URL']));
  const tags = toTags(valueOf(data, ['property_tags', 'tags', 'Tags']));
  if (!title && !summary) continue;
  items.push({ id: j.id, title, source, summary, tags, url });
}
return [{ json: { date: today, items: items.slice(0, 20), count: items.length } }];

const incoming = $input.first()?.json || {};
if (Array.isArray(incoming.blocks) && incoming.blocks.length) {
  return $input.all();
}

const prepared = $('Préparer').first().json || {};
const items = Array.isArray(prepared.items) ? prepared.items : [];
const date = prepared.date || new Date().toLocaleDateString('fr-FR');

const capUtf16 = (value, limit = 1900) => {
  const s = (value ?? '').toString();
  let units = 0;
  let out = '';
  for (const ch of s) {
    const u = ch.codePointAt(0) > 0xffff ? 2 : 1;
    if (units + u > limit) break;
    out += ch;
    units += u;
  }
  return out;
};

const richText = (content) => [{ type: 'text', text: { content: capUtf16(content || '') } }];
const block = (type, content) => ({ object: 'block', type, [type]: { rich_text: richText(content) } });
const divider = () => ({ object: 'block', type: 'divider', divider: {} });

const blocks = [
  block('heading_2', `Daily Brief - ${date}`),
  block('paragraph', 'Fallback local : le bridge /brief n’a pas renvoyé de blocs, donc ce brief reprend uniquement les captures Notion disponibles.'),
  block('heading_3', 'Inbox du jour'),
];

if (!items.length) {
  blocks.push(block('paragraph', 'RAS'));
} else {
  for (const item of items) {
    const title = item.title || '(sans titre)';
    const summary = item.summary || 'Pas de résumé disponible.';
    const source = item.source ? ` · Source: ${item.source}` : '';
    const tags = Array.isArray(item.tags) && item.tags.length ? ` · Tags: ${item.tags.join(', ')}` : '';
    blocks.push(block('bulleted_list_item', `${title} - ${summary}${source}${tags}`));
  }
}

blocks.push(
  block('heading_3', 'Action du jour'),
  block('paragraph', items.length ? 'Relire les captures ci-dessus et choisir celle qui soutient le mieux les objectifs actifs.' : 'Aucune capture à traiter.'),
  divider()
);

return [{ json: { ok: true, fallback: true, brief: `Fallback local - ${date}`, blocks, count: items.length } }];

const STALE_DAYS = 7;
const COMPLETED_LOOKBACK_DAYS = 3;
const nowD = new Date();
const sourceNodes = ['Notes — blocs', 'Contexte système — blocs', 'Objectifs — actifs', 'Tâches — ouvertes'];
for (const name of sourceNodes) { if ($(name).all().some(i => i.json && i.json.error)) throw new Error('Notion read failed: ' + name); }
const getText = (block) => { if (typeof block.content === 'string') return block.content; const type = block.type; const c = block[type]; if (!c) return ''; const rt = c.rich_text || []; return rt.map(t => t.plain_text || '').join(''); };
const isChecked = (block) => (block.checked !== undefined ? block.checked : ((block.to_do || {}).checked || false));
const noteBlocks = $('Notes — blocs').all().map(i => i.json).filter(b => b && b.type);
let section = null; const aujourdHui = [], journal = [], todos = []; let journalDate = null;
for (const block of noteBlocks) {
  const text = getText(block); const type = block.type;
  if (type === 'heading_2' || type === 'heading_1') {
    if (text.includes('Aujourd')) section = 'aujourdhui';
    else if (text.includes('Journal')) section = 'journal';
    else if (text.includes('Todo') || text.includes('✅')) section = 'todos';
    else if (text.includes('Archive') || text.includes('🗄')) break;
    else section = null;
    continue;
  }
  if (type === 'heading_3' && section === 'journal') { if (journalDate !== null) break; journalDate = text; continue; }
  if (!text) continue;
  if (section === 'aujourdhui') aujourdHui.push(text);
  else if (section === 'journal' && journalDate !== null) journal.push(text);
  else if (section === 'todos') { todos.push((isChecked(block) ? '✓' : '☐') + ' ' + text); }
}
const parts = [];
if (aujourdHui.length) parts.push('Notes du jour :\n' + aujourdHui.map(l => '- ' + l).join('\n'));
if (journalDate && journal.length) parts.push('Journal (' + journalDate + ') :\n' + journal.map(l => '- ' + l).join('\n'));
if (todos.length) parts.push('Todos en cours :\n' + todos.join('\n'));
const context = parts.join('\n\n').slice(0, 3000);
const systemLines = [];
for (const block of $('Contexte système — blocs').all().map(i => i.json).filter(b => b && b.type)) {
  const text = getText(block).trim();
  if (!text) continue;
  systemLines.push(block.type.startsWith('heading_') ? '## ' + text : '- ' + text);
}
const system_context = systemLines.join('\n').slice(0, 12000);
const norm = (s) => s.toString().toLowerCase().normalize('NFD').replace(/[̀-ͯ]/g, '').replace(/[^a-z0-9]+/g, '');
const toText = (value) => { if (value === undefined || value === null) return ''; if (Array.isArray(value)) return value.map(toText).filter(Boolean).join(', '); if (typeof value === 'object') return value.name || value.value || value.plain_text || value.start || (value.text && value.text.content) || ''; return value.toString(); };
const mapOf = (j) => { const m = {}; const src = { ...(j.properties || {}), ...j }; for (const k of Object.keys(src)) { const key = k.startsWith('property_') ? k.slice(9) : k; m[norm(key)] = src[k]; } return m; };
const field = (m, names) => { for (const n of names) { const v = toText(m[n]); if (v) return v; } return ''; };
const objectives = [];
for (const it of $('Objectifs — actifs').all()) {
  const m = mapOf(it.json || {});
  const nom = field(m, ['nom', 'name']);
  if (!nom) continue;
  const statut = field(m, ['statut']);
  if (statut && statut !== 'Actif') continue;
  objectives.push({ nom, domaine: field(m, ['domaine']), priorite: field(m, ['priorite', 'priorit']), etat: field(m, ['etatactuel', 'tatactuel']), prochaine_etape: field(m, ['prochaineetape', 'prochainetape']), horizon: field(m, ['horizon']) });
}
const open_tasks = [];
for (const it of $('Tâches — ouvertes').all()) {
  const m = mapOf(it.json || {});
  const titre = field(m, ['tache', 'tche', 'name']);
  if (!titre) continue;
  const statut = field(m, ['statut']);
  if (statut && statut !== 'À faire') continue;
  const d = field(m, ['proposeele', 'proposele']);
  if (d) { const age = (nowD - new Date(d)) / 86400000; if (age > STALE_DAYS) continue; }
  open_tasks.push({ titre, domaine: field(m, ['domaine']), pourquoi: field(m, ['pourquoi']), feedback: field(m, ['retour', 'resultat', 'bilan', 'blocage']), propose_le: d });
}
const completed_tasks = [];
for (const it of $('Tâches — ouvertes').all()) {
  const m = mapOf(it.json || {});
  const titre = field(m, ['tache', 'tche', 'name']);
  if (!titre || field(m, ['statut']) !== 'Fait') continue;
  const completedAt = field(m, ['faitele', 'termineele', 'terminele', 'completedat', 'lasteditedtime']);
  if (!completedAt) continue;
  const age = (nowD - new Date(completedAt)) / 86400000;
  if (!Number.isFinite(age) || age < 0 || age > COMPLETED_LOOKBACK_DAYS) continue;
  completed_tasks.push({ titre, domaine: field(m, ['domaine']), pourquoi: field(m, ['pourquoi']), feedback: field(m, ['retour', 'resultat', 'bilan', 'blocage']), terminee_le: completedAt });
}
completed_tasks.sort((a, b) => new Date(b.terminee_le) - new Date(a.terminee_le));
const prepared = $('Préparer').first().json || {};
return [{ json: { ...prepared, context, system_context, objectives, open_tasks, completed_tasks: completed_tasks.slice(0, 10) } }];

const out = $('Brief fallback si Claude KO').first().json || {};
const tasks = Array.isArray(out.tasks) ? out.tasks : [];
const open = (($('Enrichir payload').first().json || {}).open_tasks) || [];
const norm = (s) => (s || '').toString().toLowerCase().normalize('NFD').replace(/[̀-ͯ]/g, '').replace(/[^a-z0-9]+/g, '');
const blocked = new Set(open.map(t => norm(t.titre)));
const seen = new Set();
const res = [];
for (const t of tasks) {
  if (!t || !t.titre) continue;
  const k = norm(t.titre);
  if (!k || blocked.has(k) || seen.has(k)) continue;
  seen.add(k);
  res.push({ json: { titre: t.titre, domaine: t.domaine || 'Knowledge', pourquoi: t.pourquoi || '' } });
}
return res;

const fb = $('Brief fallback si Claude KO').first().json || {};
const blocks = Array.isArray(fb.blocks) ? fb.blocks : [];
const firstBlocks = $('Brief: 1er bloc').all().map(i => i.json).filter(b => b && b.id);
const after = firstBlocks.length ? firstBlocks[0].id : null;
const children = [{ object: 'block', type: 'divider', divider: {} }].concat(blocks);
const body = after ? { children, after } : { children };
return [{ json: { body } }];

const STALE_DAYS = 7;
const nowD = new Date();
const norm = (s) => s.toString().toLowerCase().normalize('NFD').replace(/[̀-ͯ]/g, '').replace(/[^a-z0-9]+/g, '');
const toText = (value) => { if (value === undefined || value === null) return ''; if (Array.isArray(value)) return value.map(toText).filter(Boolean).join(', '); if (typeof value === 'object') return value.name || value.value || value.plain_text || value.start || (value.text && value.text.content) || ''; return value.toString(); };
const mapOf = (j) => { const m = {}; const src = { ...(j.properties || {}), ...j }; for (const k of Object.keys(src)) { const key = k.startsWith('property_') ? k.slice(9) : k; m[norm(key)] = src[k]; } return m; };
const field = (m, names) => { for (const n of names) { const v = toText(m[n]); if (v) return v; } return ''; };
const out = [];
for (const it of $('Tâches — ouvertes').all()) {
  const j = it.json || {}; if (!j.id) continue;
  const m = mapOf(j);
  if (field(m, ['statut']) !== 'À faire') continue;
  const d = field(m, ['proposeele', 'proposele']);
  if (!d) continue;
  const age = (nowD - new Date(d)) / 86400000;
  if (age > STALE_DAYS) out.push({ json: { id: j.id } });
}
return out;

const fb = $('Brief fallback si Claude KO').first().json || {};
const engine = fb.engine || (fb.fallback ? 'none' : 'claude');
const context_source = fb.context_source || 'fallback';
if (engine === 'claude' && context_source === 'notion') return [];
const date = $('Préparer').first().json.date || new Date().toLocaleDateString('fr-FR');
return [{ json: { engine, context_source, date } }];
